// Variables globales let montantTotal = 0; let selectedMember = null; // Initialiser au chargement $(document).ready(function() { // Initialiser Select2 $('#membre_id').select2({ placeholder: '-- Sélectionner dans la liste --', width: '100%', allowClear: true }).on('change', function() { updateMemberInfo(); }); // Initialiser la date d'échéance updateEcheanceDate(); // Écouter le changement d'année pour mettre à jour la date d'échéance $('#annee_cotisation').on('change', function() { updateEcheanceDate(); }); // Écouter le changement du type de versement $('input[name="type_versement"]').on('change', function() { updateMontantInput(); }); // Écouter le changement de montant $('#montant').on('input', function() { calculerReste(); }); // Initialiser l'état du montant updateMontantInput(); // Initialiser la date d'aujourd'hui si vide if (!$('#date_paiement').val()) { $('#date_paiement').val('{{ date('Y-m-d') }}'); } }); // Mettre à jour les informations du membre sélectionné function updateMemberInfo() { const membreSelect = document.getElementById('membre_id'); const selectedOption = membreSelect.options[membreSelect.selectedIndex]; if (selectedOption && selectedOption.value) { const plan = selectedOption.getAttribute('data-plan') || 'Non défini'; montantTotal = parseFloat(selectedOption.getAttribute('data-montant')) || 0; selectedMember = selectedOption.value; // Mettre à jour l'affichage $('#display-categorie').text(plan); $('#display-montant-auto').text(formatCurrency(montantTotal) + ' CFA'); $('#montant_total_attendu').val(montantTotal); // Mettre à jour le montant selon le type de versement updateMontantInput(); } else { $('#display-categorie').text('---'); $('#display-montant-auto').text('0 CFA'); $('#montant_total_attendu').val(0); montantTotal = 0; selectedMember = null; // Réinitialiser le montant $('#montant').val(''); $('#display-restant').text('0 CFA'); $('#reste_a_payer').val(0); } } // Mettre à jour l'état du champ montant selon le type de versement function updateMontantInput() { const typeVersement = $('input[name="type_versement"]:checked').val(); if (typeVersement === 'TOTAL' && montantTotal > 0) { $('#montant').val(montantTotal).prop('readonly', true); $('#status').val('TOTAL'); } else { $('#montant').val('').prop('readonly', false); $('#montant').focus(); $('#status').val('PARTIEL'); } calculerReste(); } // Calculer le reste à payer function calculerReste() { const montantPaye = parseFloat($('#montant').val()) || 0; const reste = montantTotal - montantPaye; const displayRestant = $('#display-restant'); const resteInput = $('#reste_a_payer'); // Mettre à jour l'affichage if (reste > 0) { displayRestant.text(formatCurrency(reste) + ' CFA'); displayRestant.css('color', '#d9534f'); // Rouge pour dette resteInput.val(reste); $('#status').val('PARTIEL'); } else if (reste === 0 && montantPaye > 0) { displayRestant.text('0 CFA'); displayRestant.css('color', '#5cb85c'); // Vert pour payé resteInput.val(0); $('#status').val('TOTAL'); } else if (reste < 0) { displayRestant.text(formatCurrency(Math.abs(reste)) + ' CFA (excédent)'); displayRestant.css('color', '#f0ad4e'); // Orange pour excédent resteInput.val(0); $('#status').val('TOTAL'); } else { displayRestant.text('0 CFA'); displayRestant.css('color', '#333'); resteInput.val(0); } } // Mettre à jour la date d'échéance (31 mars de l'année suivante) function updateEcheanceDate() { const annee = parseInt($('#annee_cotisation').val()) || new Date().getFullYear(); const dateEcheance = new Date(annee + 1, 2, 31); // 2 = mars (0-indexé) $('#date_echeance').val(dateEcheance.toISOString().split('T')[0]); } // Formater la devise function formatCurrency(amount) { return new Intl.NumberFormat('fr-FR', { minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(amount); } // Valider les données avant enregistrement function validateForm() { const errors = []; // Validation du membre if (!$('#membre_id').val()) { errors.push('Veuillez sélectionner un membre'); } // Validation du montant const montantPaye = parseFloat($('#montant').val()) || 0; if (montantPaye <= 0) { errors.push('Le montant payé doit être supérieur à 0'); } // Validation du mode de paiement const modePaiement = $('#mode_paiement').val(); if (!modePaiement) { errors.push('Veuillez sélectionner un mode de paiement'); } // Validation de la date if (!$('#date_paiement').val()) { errors.push('Veuillez saisir une date de paiement'); } else { const datePaiement = new Date($('#date_paiement').val()); const aujourdhui = new Date(); if (datePaiement > aujourdhui.setHours(23, 59, 59, 999)) { errors.push('La date de paiement ne peut pas être dans le futur'); } } return errors; } // Enregistrer avec serialize() function saveRecord() { // Validation const errors = validateForm(); if (errors.length > 0) { errors.forEach(error => { toastr.error(error, 'Erreur de validation', { timeOut: 5000, closeButton: true }); }); return; } // S'assurer que les calculs sont à jour calculerReste(); // Afficher l'indicateur de chargement const btn = $('button[onclick="saveRecord()"]'); const originalText = btn.html(); btn.html('<i class="voyager-refresh voyager-animate-spin"></i> Enregistrement...'); btn.prop('disabled', true); // Préparer et envoyer les données $.ajax({ url: $('#cotisationForm').attr('action'), method: 'POST', data: $('#cotisationForm').serialize(), dataType: 'json', headers: { 'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content') }, success: function(response) { if (response.success) { toastr.success(response.message || 'Cotisation enregistrée avec succès', 'Succès', { timeOut: 3000 }); // Réinitialiser le formulaire après 2 secondes setTimeout(() => { resetForm(); // Rediriger si spécifié if (response.redirect) { window.location.href = response.redirect; } }, 2000); } else { toastr.error(response.message || 'Erreur lors de l\'enregistrement', 'Erreur', { timeOut: 5000 }); } }, error: function(xhr) { let errorMessage = 'Une erreur est survenue lors de l\'enregistrement'; if (xhr.status === 422 && xhr.responseJSON && xhr.responseJSON.errors) { // Erreurs de validation Laravel const errors = xhr.responseJSON.errors; errorMessage = Object.values(errors)[0][0]; } else if (xhr.responseJSON && xhr.responseJSON.message) { errorMessage = xhr.responseJSON.message; } else if (xhr.status === 419) { errorMessage = 'Session expirée. Veuillez rafraîchir la page.'; } toastr.error(errorMessage, 'Erreur', { timeOut: 5000, closeButton: true }); console.error('Erreur AJAX:', xhr); }, complete: function() { // Restaurer le bouton btn.html(originalText); btn.prop('disabled', false); } }); } // Réinitialiser le formulaire function resetForm() { // Réinitialiser Select2 $('#membre_id').val('').trigger('change'); // Réinitialiser les champs $('#display-categorie').text('---'); $('#display-montant-auto').text('0 CFA'); $('#display-restant').text('0 CFA'); $('input[name="type_versement"][value="TOTAL"]').prop('checked', true); $('#reference').val(''); $('#montant').val(''); $('#reste_a_payer').val('0'); $('#mode_paiement').val(''); $('#date_paiement').val('{{ date('Y-m-d') }}'); $('#observation').val(''); // Réinitialiser les variables montantTotal = 0; selectedMember = null; // Mettre à jour les contrôles updateMontantInput(); updateEcheanceDate(); toastr.info('Formulaire réinitialisé', 'Information', { timeOut: 2000 }); } 